Consider this TypeScript code:

```typescript
class Animal {
  speak(): string {
    return "some sound";
  }
}

class Cat extends Animal {
  speak(): string {
    return "meow";
  }
}

const animal: Animal = new Cat();
console.log(animal.speak());
```

What is printed?

Consider this TypeScript code:

```typescript
interface Flyable {
  fly(): void;
}

interface Swimmable {
  swim(): void;
}

class Duck implements Flyable, Swimmable {
  fly(): void { console.log("flying"); }
  swim(): void { console.log("swimming"); }
}
```

A TypeScript class can implement more than one interface at the same time.

Consider this TypeScript code:

```typescript
interface Greetable {
  greet(): string;
}

class EnglishGreeter implements Greetable {
  greet(): string { return "Hello"; }
}

class SpanishGreeter implements Greetable {
  greet(): string { return "Hola"; }
}

function sayHi(g: Greetable): string {
  return g.greet();
}

console.log(sayHi(new SpanishGreeter()));
```

What is printed?

